(function(){function q(id){return document.getElementById(id)}function fmtTime(d){return d.toLocaleTimeString('uk-UA',{hour:'2-digit',minute:'2-digit',second:'2-digit'})}q('clickMe1').addEventListener('click',function(){document.getElementById('output').textContent=fmtTime(new Date())});q('clickMe2').addEventListener('click',function(){const n=new Date();document.getElementById('output').textContent=fmtTime(n)+' '+n.toLocaleDateString('uk-UA',{weekday:'long'})});q('clickMe3').addEventListener('click',function(){const n=new Date();document.getElementById('output').textContent=n.toLocaleDateString('uk-UA',{weekday:'long',year:'numeric',month:'long',day:'numeric'})+' о '+fmtTime(n)});(function(){const container=q('cat-container'),cat1=q('cat'),cat2=q('cat2'),mouse=q('mouse');let timers=[],foods=[];const clamp=(v,a,b)=>Math.max(a,Math.min(b,v));function clearAll(){timers.forEach(t=>clearTimeout(t));timers=[]}function moveMouseOnce(){if(!mouse||!container)return;const c=container.getBoundingClientRect(),m=mouse.getBoundingClientRect();const cheese=container.querySelector('.cheese');if(cheese){const ch=cheese.getBoundingClientRect(),mCx=(m.left-c.left)+m.width/2,mCy=(m.top-c.top)+m.height/2,chCx=(ch.left-c.left)+ch.width/2,chCy=(ch.top-c.top)+ch.height/2;const dx=chCx-mCx,dy=chCy-mCy,dist=Math.sqrt(dx*dx+dy*dy)||1,step=Math.min(dist,96);const nx=clamp((m.left-c.left)+(dx/dist)*step,0,Math.max(0,c.width-m.width)),ny=clamp((m.top-c.top)+(dy/dist)*step,0,Math.max(0,c.height-m.height));mouse.style.left=nx+'px';mouse.style.top=ny+'px';mouse.style.transform=(dx>=0)?'scaleX(1)':'scaleX(-1)';if(dist<36){cheese.style.transition='transform .12s ease, opacity .12s ease';cheese.style.transform='scale(.2)';cheese.style.opacity='0';setTimeout(()=>{try{cheese.remove()}catch(e){}},140)}return}const maxX=Math.max(0,c.width-m.width),maxY=Math.max(0,c.height-m.height),x=Math.random()*maxX,y=Math.random()*maxY;mouse.style.left=x+'px';mouse.style.top=y+'px';mouse.style.transform=Math.random()>.5?'scaleX(1)':'scaleX(-1)'}function scheduleMouse(){function s(){moveMouseOnce();const next=container.querySelector('.cheese')?(40+Math.random()*60):(100+Math.random()*400);timers.push(setTimeout(s,Math.floor(next)))}s()}if(container){container.addEventListener('click',function(e){const cRect=container.getBoundingClientRect();if(e.shiftKey){const prev=container.querySelector('.cheese');if(prev)prev.remove();const size=28,x=e.clientX-cRect.left-size/2,y=e.clientY-cRect.top-size/2;const ch=document.createElement('div');ch.className='cheese';ch.dataset.cheeseId='ch'+Date.now();ch.style.left=Math.max(0,Math.min(cRect.width-size,x))+'px';ch.style.top=Math.max(0,Math.min(cRect.height-size,y))+'px';container.appendChild(ch);return}const size=18,x=e.clientX-cRect.left-size/2,y=e.clientY-cRect.top-size/2,id='f'+Date.now()+Math.floor(Math.random()*1e3),el=document.createElement('div');el.className='food owner1';el.dataset.foodId=id;el.dataset.owner='1';el.style.left=Math.max(0,Math.min(cRect.width-size,x))+'px';el.style.top=Math.max(0,Math.min(cRect.height-size,y))+'px';container.appendChild(el);foods.push(id);requestAnimationFrame(()=>{el.style.transform='scale(1.08)';setTimeout(()=>el.style.transform='scale(1)',120)})});container.addEventListener('contextmenu',function(e){e.preventDefault();const cRect=container.getBoundingClientRect(),size=18,x=e.clientX-cRect.left-size/2,y=e.clientY-cRect.top-size/2,id='f'+Date.now()+Math.floor(Math.random()*1e3),el=document.createElement('div');el.className='food owner2';el.dataset.foodId=id;el.dataset.owner='2';el.style.left=Math.max(0,Math.min(cRect.width-size,x))+'px';el.style.top=Math.max(0,Math.min(cRect.height-size,y))+'px';container.appendChild(el);foods.push(id);requestAnimationFrame(()=>{el.style.transform='scale(1.08)';setTimeout(()=>el.style.transform='scale(1)',120)})})}function chaseStep(cat,speed,jitter){if(!cat||!container)return;const cRect=container.getBoundingClientRect(),catRect=cat.getBoundingClientRect(),owner=(cat===cat1)?'1':'2';foods=foods.filter(id=>document.querySelector('[data-food-id="'+id+'"]'));if(foods.length){let nearest=null,nearestId=null,best=1/0,catCx=(catRect.left-cRect.left)+catRect.width/2,catCy=(catRect.top-cRect.top)+catRect.height/2;foods.forEach(id=>{const f=document.querySelector('[data-food-id="'+id+'"]');if(!f)return;if(f.dataset.owner!==owner)return;const fr=f.getBoundingClientRect(),fx=(fr.left-cRect.left)+fr.width/2,fy=(fr.top-cRect.top)+fr.height/2,dx=fx-catCx,dy=fy-catCy,d=Math.sqrt(dx*dx+dy*dy);if(d<best){best=d;nearest=f;nearestId=id}});if(nearest){const fRect=nearest.getBoundingClientRect(),fx=(fRect.left-cRect.left)+fRect.width/2,fy=(fRect.top-cRect.top)+fRect.height/2,dx=fx-((catRect.left-cRect.left)+catRect.width/2),dy=fy-((catRect.top-cRect.top)+catRect.height/2),stepX=dx*Math.min(1,speed*1.6)+(Math.random()-.5)*jitter,stepY=dy*Math.min(1,speed*1.6)+(Math.random()-.5)*jitter,newL=clamp((catRect.left-cRect.left)+stepX,0,Math.max(0,cRect.width-catRect.width)),newT=clamp((catRect.top-cRect.top)+stepY,0,Math.max(0,cRect.height-catRect.height));cat.style.left=newL+'px';cat.style.top=newT+'px';cat.style.transform=(dx>=0)?'scaleX(1)':'scaleX(-1)';if(best<36){nearest.style.transition='transform .12s ease, opacity .12s ease';nearest.style.transform='scale(.2)';nearest.style.opacity='0';setTimeout(()=>{try{nearest.remove()}catch(e){}},140);foods=foods.filter(id=>id!==nearestId)}return}}if(!mouse)return;const mR=mouse.getBoundingClientRect(),catCx=(catRect.left-cRect.left)+catRect.width/2,catCy=(catRect.top-cRect.top)+catRect.height/2,mCx=(mR.left-cRect.left)+mR.width/2,mCy=(mR.top-cRect.top)+mR.height/2,dx=mCx-catCx,dy=mCy-catCy,stepX=dx*speed+(Math.random()-.5)*jitter,stepY=dy*speed+(Math.random()-.5)*jitter,newL=clamp((catRect.left-cRect.left)+stepX,0,Math.max(0,cRect.width-catRect.width)),newT=clamp((catRect.top-cRect.top)+stepY,0,Math.max(0,cRect.height-catRect.height));cat.style.left=newL+'px';cat.style.top=newT+'px';cat.style.transform=(dx>=0)?'scaleX(1)':'scaleX(-1)'}function scheduleChase(cat,minMs,maxMs,speed,jitter){function s(){chaseStep(cat,speed,jitter);const next=Math.floor(minMs+Math.random()*(maxMs-minMs));timers.push(setTimeout(s,next))}s()}clearAll();scheduleMouse();scheduleChase(cat1,300,800,.28,30);scheduleChase(cat2,220,640,.4,50);if(container){container.addEventListener('mouseenter',function(){clearAll()});container.addEventListener('mouseleave',function(){clearAll();scheduleMouse();scheduleChase(cat1,300,800,.28,30);scheduleChase(cat2,220,640,.4,50)})}})();})();